const message = $input.first().json;
const msgText = (message.message || '').toUpperCase().trim();
const from = message.from;

let response = '';
let command = '';

switch(msgText) {
  case 'HI':
  case 'HELLO':
  case 'START':
    response = 'Welcome to NursingCare.pk! 👋\n\nSend:\n- IN : Check in\n- OUT : Check out\n- LEAVE : Request leave\n- SHIFT : View shift info\n- HELP : Show this menu';
    command = 'HELP';
    break;
  case 'IN':
    response = '✅ Check-in recorded!\nHave a great shift!';
    command = 'IN';
    break;
  case 'OUT':
    response = '✅ Check-out recorded!\nThank you for your work today!';
    command = 'OUT';
    break;
  case 'LEAVE':
    response = '📝 Leave Request\n\nPlease send:\nLEAVE [type] [dates] [reason]\n\nExample: LEAVE sick 15-03 fever';
    command = 'LEAVE';
    break;
  case 'SHIFT':
    response = '📅 Shift Info\n\nDay Shift: 08:00 - 20:00\nNight Shift: 20:00 - 08:00';
    command = 'SHIFT';
    break;
  case 'HELP':
    response = '📋 Commands:\n\n- IN : Check in to shift\n- OUT : Check out from shift\n- LEAVE : Request leave\n- SHIFT : View shift times\n- HELP : Show this menu';
    command = 'HELP';
    break;
  default:
    response = '❓ Unknown command.\n\nSend HELP for menu.';
    command = 'UNKNOWN';
}

return [{
  from: from,
  message: response,
  command: command,
  originalMessage: msgText
}];
